      if (!context.user) throw new AuthenticationError('Not authenticated');
      return UserService.updateProfile(context.user.id, input);
    },
  },

  User: {
    posts: (parent, { first, after }) => {
      return PostService.findByAuthor(parent.id, { first, after });
    },
  },
};

