import DataLoader from 'dataloader';
import type { PrismaClient, User, Post } from '@prisma/client';

export function createLoaders(db: PrismaClient) {
  return {
    userLoader: new DataLoader<string, User | null>(async (ids) => {
      const users = await db.user.findMany({
        where: { id: { in: [...ids] } },
      });
      const userMap = new Map(users.map((u) => [u.id, u]));
      return ids.map((id) => userMap.get(id) ?? null);
    }),

    postsByAuthorLoader: new DataLoader<string, Post[]>(async (authorIds) => {
      const posts = await db.post.findMany({
        where: { authorId: { in: [...authorIds] } },
      });
      const postMap = new Map<string, Post[]>();
      posts.forEach((post) => {
        const existing = postMap.get(post.authorId) ?? [];
        existing.push(post);
        postMap.set(post.authorId, existing);
      });
      return authorIds.map((id) => postMap.get(id) ?? []);
    }),
  };
}

// In resolvers:
const resolvers = {
  Post: {
    author: (parent: Post, _args: unknown, context: GraphQLContext) => {
      return context.loaders.userLoader.load(parent.authorId);
    },
  },
  User: {
    posts: (parent: User, _args: unknown, context: GraphQLContext) => {
      return context.loaders.postsByAuthorLoader.load(parent.id);
    },
  },
};

