import { GraphQLError } from 'graphql';

// Custom error classes
export class AuthenticationError extends GraphQLError {
  constructor(message = 'Not authenticated') {
    super(message, {
      extensions: { code: 'UNAUTHENTICATED', http: { status: 401 } },
    });
  }
}

export class ForbiddenError extends GraphQLError {
  constructor(message = 'Not authorized') {
    super(message, {
      extensions: { code: 'FORBIDDEN', http: { status: 403 } },
    });
  }
}

export class NotFoundError extends GraphQLError {
  constructor(resource: string) {
    super(`${resource} not found`, {
      extensions: { code: 'NOT_FOUND', http: { status: 404 } },
    });
  }
}

export class ValidationError extends GraphQLError {
  constructor(message: string, fields: Record<string, string[]>) {
    super(message, {
      extensions: { code: 'VALIDATION_ERROR', fields, http: { status: 400 } },
    });
  }
}

// Usage in resolvers
const resolvers = {
  Mutation: {
    updatePost: async (_parent: unknown, { id, input }: any, context: GraphQLContext) => {
      if (!context.user) throw new AuthenticationError();
      const post = await context.db.post.findUnique({ where: { id } });
      if (!post) throw new NotFoundError('Post');
      if (post.authorId !== context.user.id) throw new ForbiddenError();
      return context.db.post.update({ where: { id }, data: input });
    },
  },
};

