// src/auth.ts
import jwt from 'jsonwebtoken';
import { AuthenticationError } from './errors';
import type { GraphQLContext } from './context';

const JWT_SECRET = process.env.JWT_SECRET!;

export interface TokenPayload {
  sub: string;
  email: string;
  role: string;
  iat: number;
  exp: number;
}

export function verifyToken(token: string): TokenPayload {
  try {
    return jwt.verify(token, JWT_SECRET) as TokenPayload;
  } catch (error) {
    throw new AuthenticationError('Invalid or expired token');
  }
}

export function requireAuth(context: GraphQLContext) {
  if (!context.user) {
    throw new AuthenticationError();
  }
  return context.user;
}

export function requireRole(context: GraphQLContext, ...roles: string[]) {
  const user = requireAuth(context);
  if (!roles.includes(user.role)) {
    throw new ForbiddenError(`Requires role: ${roles.join(' or ')}`);
  }
  return user;
}

// Usage in resolvers
const resolvers = {
  Query: {
    me: (_parent: unknown, _args: unknown, context: GraphQLContext) => {
      const user = requireAuth(context);
      return context.db.user.findUnique({ where: { id: user.id } });
    },
  },
  Mutation: {
    deleteUser: async (_parent: unknown, { id }: { id: string }, context: GraphQLContext) => {
      requireRole(context, 'ADMIN');
      await context.db.user.delete({ where: { id } });
      return true;
    },
  },
};

