// src/auth/permissions.ts
import { GraphQLError } from 'graphql';
import type { GraphQLContext } from '../context';

type ResolverFn = (parent: any, args: any, context: GraphQLContext, info: any) => any;

export function authorized(roles: string[]) {
  return (resolverFn: ResolverFn): ResolverFn => {
    return (parent, args, context, info) => {
      if (!context.user) {
        throw new GraphQLError('Not authenticated', {
          extensions: { code: 'UNAUTHENTICATED' },
        });
      }
      if (roles.length > 0 && !roles.includes(context.user.role)) {
        throw new GraphQLError('Not authorized', {
          extensions: { code: 'FORBIDDEN' },
        });
      }
      return resolverFn(parent, args, context, info);
    };
  };
}

// Resolvers with field-level authorization
const resolvers = {
  Query: {
    users: authorized(['ADMIN'])(
      (_parent, { first, after }, context) => {
        return context.db.user.findMany({ take: first });
      }
    ),
  },
  User: {
    // Only the user themselves or admins can see email
    email: (parent: any, _args: unknown, context: GraphQLContext) => {
      if (context.user?.id === parent.id || context.user?.role === 'ADMIN') {
        return parent.email;
      }
      return null;
    },
    // Only admins can see role
    role: (parent: any, _args: unknown, context: GraphQLContext) => {
      if (context.user?.role === 'ADMIN') {
        return parent.role;
      }
      return null;
    },
  },
};

