Code Good:
const typeDefs = gql`
  type PageInfo {
    hasNextPage: Boolean!
    hasPreviousPage: Boolean!
    startCursor: String
    endCursor: String
  }

  type PostEdge {
    cursor: String!
    node: Post!
  }

  type PostConnection {
    edges: [PostEdge!]!
    pageInfo: PageInfo!
    totalCount: Int!
  }

  type Query {
    posts(first: Int = 20, after: String): PostConnection!
  }
`;

// Resolver implementation
function encodeCursor(id: string): string {
  return Buffer.from(`cursor:${id}`).toString('base64');
}

function decodeCursor(cursor: string): string {
  const decoded = Buffer.from(cursor, 'base64').toString('utf-8');
  return decoded.replace('cursor:', '');
}

const resolvers = {
  Query: {
    posts: async (_parent: unknown, { first, after }: { first: number; after?: string }, context: GraphQLContext) => {
      const take = Math.min(first, 100);
      const where: any = {};

      if (after) {
        where.id = { gt: decodeCursor(after) };
      }

      const [posts, totalCount] = await Promise.all([
        context.db.post.findMany({
          where,
          take: take + 1,
          orderBy: { id: 'asc' },
        }),
        context.db.post.count(),
      ]);

      const hasNextPage = posts.length > take;
      const edges = posts.slice(0, take).map((post) => ({
        cursor: encodeCursor(post.id),
        node: post,
      }));

      return {
        edges,
        pageInfo: {
          hasNextPage,
          hasPreviousPage: !!after,
          startCursor: edges[0]?.cursor ?? null,
          endCursor: edges[edges.length - 1]?.cursor ?? null,
        },
        totalCount,
      };
    },
  },
};

