import { mapSchema, getDirective, MapperKind } from '@graphql-tools/utils';
import { GraphQLSchema, defaultFieldResolver } from 'graphql';
import { GraphQLError } from 'graphql';

// Schema with custom directives
const typeDefs = gql`
  directive @auth(requires: Role = VIEWER) on FIELD_DEFINITION
  directive @deprecated(reason: String) on FIELD_DEFINITION
  directive @cacheControl(maxAge: Int!) on FIELD_DEFINITION

  enum Role {
    ADMIN
    EDITOR
    VIEWER
  }

  type Query {
    publicPosts: [Post!]!
    users: [User!]! @auth(requires: ADMIN)
    analytics: Analytics! @auth(requires: EDITOR) @cacheControl(maxAge: 300)
  }
`;

// Directive transformer
function authDirectiveTransformer(schema: GraphQLSchema): GraphQLSchema {
  return mapSchema(schema, {
    [MapperKind.OBJECT_FIELD]: (fieldConfig) => {
      const authDirective = getDirective(schema, fieldConfig, 'auth')?.[0];
      if (!authDirective) return fieldConfig;

      const requiredRole = authDirective.requires;
      const originalResolve = fieldConfig.resolve ?? defaultFieldResolver;

      fieldConfig.resolve = async (source, args, context, info) => {
        if (!context.user) {
          throw new GraphQLError('Not authenticated', {
            extensions: { code: 'UNAUTHENTICATED' },
          });
        }
        const roleHierarchy = ['VIEWER', 'EDITOR', 'ADMIN'];
        const userRoleIndex = roleHierarchy.indexOf(context.user.role);
        const requiredRoleIndex = roleHierarchy.indexOf(requiredRole);
        if (userRoleIndex < requiredRoleIndex) {
          throw new GraphQLError(`Requires ${requiredRole} role`, {
            extensions: { code: 'FORBIDDEN' },
          });
        }
        return originalResolve(source, args, context, info);
      };
      return fieldConfig;
    },
  });
}

