import graphqlUploadExpress from 'graphql-upload/graphqlUploadExpress.mjs';
import type { FileUpload } from 'graphql-upload/Upload.mjs';
import GraphQLUpload from 'graphql-upload/GraphQLUpload.mjs';
import { gql } from 'graphql-tag';
import { S3Client, PutObjectCommand } from '@aws-sdk/client-s3';
import { pipeline } from 'stream/promises';

const typeDefs = gql`
  scalar Upload

  type UploadResult {
    url: String!
    filename: String!
    mimetype: String!
    size: Int!
  }

  type Mutation {
    uploadFile(file: Upload!): UploadResult!
    uploadAvatar(file: Upload!): User!
  }
`;

const ALLOWED_MIME_TYPES = ['image/jpeg', 'image/png', 'image/webp'];
const MAX_FILE_SIZE = 5 * 1024 * 1024; // 5MB

const resolvers = {
  Upload: GraphQLUpload,

  Mutation: {
    uploadFile: async (_parent: unknown, { file }: { file: Promise<FileUpload> }, context: GraphQLContext) => {
      const { createReadStream, filename, mimetype } = await file;

      if (!ALLOWED_MIME_TYPES.includes(mimetype)) {
        throw new GraphQLError(`File type ${mimetype} not allowed`, {
          extensions: { code: 'BAD_USER_INPUT' },
        });
      }

      const stream = createReadStream();
      const chunks: Buffer[] = [];
      let size = 0;

      for await (const chunk of stream) {
        size += (chunk as Buffer).length;
        if (size > MAX_FILE_SIZE) {
          stream.destroy();
          throw new GraphQLError('File too large (max 5MB)', {
            extensions: { code: 'BAD_USER_INPUT' },
          });
        }
        chunks.push(chunk as Buffer);
      }

      const buffer = Buffer.concat(chunks);
      const key = `uploads/${Date.now()}-${filename}`;

      const s3 = new S3Client({});
      await s3.send(new PutObjectCommand({
        Bucket: process.env.S3_BUCKET!,
        Key: key,
        Body: buffer,
        ContentType: mimetype,
      }));

      return { url: `https://${process.env.S3_BUCKET}.s3.amazonaws.com/${key}`, filename, mimetype, size };
    },
  },
};

