import { ObjectType, Field, ID, InputType, Int, registerEnumType } from '@nestjs/graphql';
import { IsEmail, MinLength, IsOptional, MaxLength } from 'class-validator';
import { Resolver, Query, Mutation, Args, ResolveField, Parent } from '@nestjs/graphql';

enum UserRole {
  ADMIN = 'ADMIN',
  EDITOR = 'EDITOR',
  VIEWER = 'VIEWER',
}

registerEnumType(UserRole, { name: 'UserRole', description: 'User roles' });

@ObjectType({ description: 'A registered user' })
class User {
  @Field(() => ID)
  id!: string;

  @Field()
  name!: string;

  @Field()
  email!: string;

  @Field(() => UserRole)
  role!: UserRole;

  @Field(() => [Post])
  posts!: Post[];
}

@InputType()
class CreateUserInput {
  @Field()
  @MinLength(2)
  name!: string;

  @Field()
  @IsEmail()
  email!: string;

  @Field()
  @MinLength(8)
  password!: string;
}

@InputType()
class UpdateUserInput {
  @Field({ nullable: true })
  @IsOptional()
  @MinLength(2)
  name?: string;

  @Field({ nullable: true })
  @IsOptional()
  @MaxLength(500)
  bio?: string;
}

@Resolver(() => User)
class UserResolver {
  constructor(
    private readonly userService: UserService,
    private readonly postService: PostService,
  ) {}

  @Query(() => User, { nullable: true })
  async me(@CurrentUser() user: TokenPayload) {
    return this.userService.findById(user.sub);
  }

  @Mutation(() => User)
  async createUser(@Args('input') input: CreateUserInput) {
    return this.userService.create(input);
  }

  @ResolveField(() => [Post])
  async posts(@Parent() user: User) {
    return this.postService.findByAuthor(user.id);
  }
}

