import { ApolloServer } from '@apollo/server';
import { typeDefs } from '../schema';
import { resolvers } from '../resolvers';
import type { GraphQLContext } from '../context';

function createTestServer(contextValue: Partial<GraphQLContext> = {}) {
  return new ApolloServer<GraphQLContext>({
    typeDefs,
    resolvers,
  });
}

const mockUser = { id: 'user-1', email: 'test@test.com', role: 'ADMIN' };

describe('User Resolvers', () => {
  it('should return the current user for me query', async () => {
    const server = createTestServer();
    const result = await server.executeOperation(
      {
        query: `query Me {
          me {
            id
            name
            email
          }
        }`,
      },
      {
        contextValue: {
          user: mockUser,
          db: {
            user: {
              findUnique: jest.fn().mockResolvedValue({
                id: 'user-1',
                name: 'Test User',
                email: 'test@test.com',
              }),
            },
          },
        } as any,
      }
    );

    expect(result.body.kind).toBe('single');
    if (result.body.kind === 'single') {
      expect(result.body.singleResult.errors).toBeUndefined();
      expect(result.body.singleResult.data?.me).toEqual({
        id: 'user-1',
        name: 'Test User',
        email: 'test@test.com',
      });
    }
  });

  it('should return auth error when not authenticated', async () => {
    const server = createTestServer();
    const result = await server.executeOperation(
      {
        query: `mutation DeleteUser($id: ID!) {
          deleteUser(id: $id)
        }`,
        variables: { id: 'user-2' },
      },
      {
        contextValue: { user: null, db: {} } as any,
      }
    );

    if (result.body.kind === 'single') {
      expect(result.body.singleResult.errors?.[0].extensions?.code).toBe('UNAUTHENTICATED');
    }
  });
});

