import { ApolloServer } from '@apollo/server';
import { ApolloServerPluginCacheControl } from '@apollo/server/plugin/cacheControl';
import responseCachePlugin from '@apollo/server-plugin-response-cache';
import { gql } from 'graphql-tag';

const typeDefs = gql`
  enum CacheControlScope {
    PUBLIC
    PRIVATE
  }

  directive @cacheControl(
    maxAge: Int
    scope: CacheControlScope
    inheritMaxAge: Boolean
  ) on FIELD_DEFINITION | OBJECT | INTERFACE | UNION

  type PublicPost @cacheControl(maxAge: 300) {
    id: ID!
    title: String!
    content: String!
    author: PublicAuthor! @cacheControl(inheritMaxAge: true)
    viewCount: Int! @cacheControl(maxAge: 60)
  }

  type PublicAuthor @cacheControl(maxAge: 600) {
    id: ID!
    name: String!
    bio: String
  }

  type UserProfile @cacheControl(maxAge: 60, scope: PRIVATE) {
    id: ID!
    name: String!
    email: String!
    settings: UserSettings! @cacheControl(maxAge: 30, scope: PRIVATE)
  }

  type Query {
    publicPosts: [PublicPost!]! @cacheControl(maxAge: 120)
    post(id: ID!): PublicPost @cacheControl(maxAge: 300)
    me: UserProfile @cacheControl(maxAge: 0, scope: PRIVATE)
  }
`;

const server = new ApolloServer({
  typeDefs,
  resolvers,
  plugins: [
    ApolloServerPluginCacheControl({
      defaultMaxAge: 0, // Default: no caching unless explicitly set
    }),
    responseCachePlugin({
      sessionId: async (requestContext) => {
        return requestContext.request.http?.headers.get('authorization') || null;
      },
    }),
  ],
});

